9	const main = async (): Promise<void> => {
10	  try {
11	    const input = await readStdin();
12	    const scenario = JSON.parse(input);
13	    const result = runScenario(scenario);
14	    process.stdout.write(JSON.stringify(result) + "\n");
15	  } catch (err) {
16	    process.stderr.write(`${err instanceof Error ? err.message : String(err)}\n`);
17	    process.exit(1);
18	  }
19	};
