19	const LOYALTY_YEARS_THRESHOLD = 2;
20	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	  moonstone: 25,
29	};
30	
31	const INSURANCE_VALUE: Record<string, number> = {
32	  sword: 1000,
33	  amulet: 600,
34	  staff: 800,
35	  potion: 400,
36	  rune: 250,
37	  moonstone: 250,
38	};
39	
40	const DEDUCTIBLE = 100;
41	const CAP_MULTIPLIER = 2;
42	const REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD = 8;
43	const HIGH_ENCHANTMENT_REIMBURSEMENT = 0.5;
44	
45	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
46	const BLOCK_SIZE = 3;
47	const BLOCK_PREMIUM = 60;
48	
49	const isBlock = (type: string, count: number): boolean =>
50	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
51	
52	const groupPremium = (type: string, count: number): number =>
53	  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;
54	
55	const tally = <T>(values: Iterable<T>, key: (v: T) => string): Map<string, number> => {
56	  const counts = new Map<string, number>();
57	  for (const v of values) {
58	    const k = key(v);
59	    counts.set(k, (counts.get(k) ?? 0) + 1);
60	  }
61	  return counts;
62	};
63	
64	const countByType = (items: Item[]): Map<string, number> =>
65	  tally(items, (i) => i.type);
66	
67	const sumBasePremiumsByGroup = (items: Item[]): number =>
68	  [...countByType(items)].reduce(
69	    (total, [type, count]) => total + groupPremium(type, count),
70	    0,
71	  );
72	
73	const isCursed = (item: Item): boolean => item.cursed === true;
74	const isHighlyEnchanted = (item: Item): boolean =>
75	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
76	const isLoyalCustomer = (customer: Customer): boolean =>
77	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
78	
79	const rateIf = (condition: boolean, rate: number): number =>
80	  condition ? rate : 0;
81	
82	const surchargeRateFor = (item: Item): number =>
83	  rateIf(isCursed(item), CURSE_SURCHARGE)
84	  + rateIf(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);
85	
86	const perItemSurcharges = (items: Item[]): number =>
87	  items.reduce(
88	    (total, item) => total + BASE_PREMIUM[item.type] * surchargeRateFor(item),
89	    0,
90	  );
91	
92	const policyWideAdjustments = (
93	  policyBase: number,
94	  customer: Customer,
95	  isFollowUp: boolean,
96	): number => {
97	  const netRate =
98	    FIRST_INSURANCE_SURCHARGE
99	    - rateIf(isLoyalCustomer(customer), LOYALTY_DISCOUNT)
100	    - rateIf(isFollowUp, FOLLOWUP_CONTRACT_DISCOUNT);
101	  return policyBase * netRate;
102	};
103	
104	const quotePremiumFor = (
105	  customer: Customer,
106	  { items }: QuoteStep,
107	  isFollowUp: boolean,
108	): QuoteResult => {
109	  const policyBase = sumBasePremiumsByGroup(items);
110	  const total =
111	    policyBase
112	    + perItemSurcharges(items)
113	    + policyWideAdjustments(policyBase, customer, isFollowUp)
114	    + PROCESSING_FEE;
115	  return { premium: Math.ceil(total) };
116	};
117	
118	const insuranceSumFor = (items: Item[]): number =>
119	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
120	
121	const assertKnownItemTypes = (items: Item[]): void => {
122	  const unknown = items.find(({ type }) => !(type in BASE_PREMIUM));
123	  if (unknown) throw new Error(`Unknown item type: ${unknown.type}`);
124	};
125	
126	const createPolicy = ({ items }: QuoteStep): Policy => {
127	  assertKnownItemTypes(items);
128	  return { items, remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER };
129	};
130	
131	const reimbursementRateFor = (item: Item): number =>
132	  (item.enchantment ?? 0) >= REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD
133	    ? HIGH_ENCHANTMENT_REIMBURSEMENT
134	    : 1;
135	
136	const findItem = (policy: Policy, itemType: string): Item => {
137	  const item = policy.items.find((i) => i.type === itemType);
138	  if (item === undefined) throw new Error(`Item not in policy: ${itemType}`);
139	  return item;
140	};
141	
142	const payoutForDamage = (policy: Policy, damage: Damage): number => {
143	  const item = findItem(policy, damage.itemType);
144	  const reimbursed = damage.amount * reimbursementRateFor(item);
145	  return Math.max(0, reimbursed - DEDUCTIBLE);
146	};
147	
148	const totalPayout = (policy: Policy, damages: Damage[]): number =>
149	  damages.reduce((sum, d) => sum + payoutForDamage(policy, d), 0);
150	
151	const capAndRoundDown = (amount: number, cap: number): number =>
152	  Math.floor(Math.min(amount, cap));
153	
154	const assertNonNegativeDamages = (damages: Damage[]): void => {
155	  const negative = damages.find((d) => d.amount < 0);
156	  if (negative) throw new Error(`Negative damage amount: ${negative.amount}`);
157	};
158	
159	const assertDamagesFitPolicy = (policy: Policy, damages: Damage[]): void => {
160	  const policyCounts = countByType(policy.items);
161	  const exceeds = [...tally(damages, (d) => d.itemType)]
162	    .find(([type, count]) => count > (policyCounts.get(type) ?? 0));
163	  if (exceeds) throw new Error(`More damage entries for ${exceeds[0]} than policy covers`);
164	};
165	
166	const settleClaim = (policy: Policy, { incident: { damages } }: ClaimStep): ClaimResult => {
167	  assertNonNegativeDamages(damages);
168	  assertDamagesFitPolicy(policy, damages);
169	  const payout = capAndRoundDown(totalPayout(policy, damages), policy.remainingCap);
170	  policy.remainingCap -= payout;
171	  return { payout, remainingCap: policy.remainingCap };
172	};
173	
174	export const runScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
175	  const policies: Policy[] = [];
176	  const handle = (step: Step): StepResult => {
177	    if (step.op === "quote") {
178	      const isFollowUp = policies.length > 0;
179	      policies.push(createPolicy(step));
180	      return quotePremiumFor(customer, step, isFollowUp);
181	    }
182	    return settleClaim(policies[step.policy], step);
183	  };
184	  return { results: steps.map(handle) };
185	};
